#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=3000005;
stack<int> st;
int n,a[N],ans[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=n;i>=1;i--)
	{
		while(!st.empty()&&a[st.top()]<=a[i]) st.pop();
		if(st.empty()) ans[i]=0;
		else ans[i]=st.top();
		st.push(i);
	}
	for(int i=1;i<=n;i++) cout<<ans[i]<<" ";
	return 0;
}
